import { forwardRef, type ButtonHTMLAttributes, type ReactNode } from 'react';

type ButtonVariant = 'primary' | 'secondary' | 'ghost' | 'danger';
type ButtonSize = 'sm' | 'md' | 'lg';

interface ButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: ButtonVariant;
  size?: ButtonSize;
  icon?: ReactNode;
  showArrow?: boolean;
  fullWidth?: boolean;
  loading?: boolean;
}

const VARIANT_STYLES: Record<ButtonVariant, string> = {
  primary:
    'border-2 border-black bg-black text-white font-bold tracking-wide hover:bg-neutral-800 active:bg-neutral-900 disabled:opacity-40 disabled:hover:bg-black',
  secondary:
    'border-2 border-black bg-white text-black font-bold tracking-wide hover:bg-neutral-100 active:bg-neutral-200 disabled:opacity-40',
  ghost:
    'text-neutral-500 hover:text-black transition-colors disabled:opacity-40',
  danger:
    'border-2 border-black bg-black text-white font-bold tracking-wide hover:bg-red-900 active:bg-red-950 disabled:opacity-40',
};

const SIZE_STYLES: Record<ButtonSize, string> = {
  sm: 'px-3 py-1.5 text-xs',
  md: 'px-4 py-2.5 text-sm',
  lg: 'px-6 py-3 text-sm',
};

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      variant = 'primary',
      size = 'md',
      icon,
      showArrow = false,
      fullWidth = false,
      loading = false,
      disabled,
      className = '',
      children,
      ...props
    },
    ref
  ) => {
    const isDisabled = disabled || loading;

    return (
      <button
        ref={ref}
        disabled={isDisabled}
        className={`
          inline-flex items-center justify-center gap-2 transition-all
          ${VARIANT_STYLES[variant]}
          ${variant !== 'ghost' ? SIZE_STYLES[size] : ''}
          ${fullWidth ? 'w-full' : ''}
          ${className}
        `}
        {...props}
      >
        {loading ? (
          <span className="h-4 w-4 animate-spin border-2 border-current border-t-transparent" />
        ) : icon ? (
          icon
        ) : showArrow ? (
          <span className="text-base">&rarr;</span>
        ) : null}
        {children}
      </button>
    );
  }
);

Button.displayName = 'Button';
